const topic = $('Loop Topics').first().json;
const prompt = $input.first().json;

// Map pillar to platform
function getPlatform(pillar) {
  const mapping = {
    'tech_insights': 'linkedin',
    'career_productivity': 'linkedin',
    'product_project': 'linkedin',
    'personal_stories': 'linkedin',
    'tech_news': 'facebook_tech',
    'tutorials': 'facebook_tech',
    'tools_tips': 'facebook_tech',
    'community': 'facebook_tech',
    'vocabulary': 'facebook_chinese',
    'grammar': 'facebook_chinese',
    'culture': 'facebook_chinese',
    'practice': 'facebook_chinese'
  };
  return mapping[pillar] || 'linkedin';
}

let userPrompt = prompt.user_prompt_template;
userPrompt = userPrompt.replace('{{topic}}', topic.topic);
userPrompt = userPrompt.replace('{{context}}', topic.notes || '');

return [{
  json: {
    topic_id: topic.id,
    system_prompt: prompt.system_prompt,
    user_prompt: userPrompt,
    topic: topic.topic,
    pillar: topic.pillar,
    platform: getPlatform(topic.pillar)
  }
}];

function escapeSql(str) {
  if (!str) return '';
  return str.replace(/'/g, "''");
}

const ollamaResponse = $input.first().json;
const preparedData = $('Prepare').first().json;

const content = ollamaResponse.message?.content || 'Generation failed - no content returned';

return [{
  json: {
    topic_id: preparedData.topic_id,
    title: escapeSql(preparedData.topic),
    platform: escapeSql(preparedData.platform),
    pillar: escapeSql(preparedData.pillar),
    content_type: escapeSql('thought_leadership'),
    generated_content: escapeSql(content),
    status: escapeSql('pending_review')
  }
}];
